#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <mpi.h>

#define FILE_NAME "input_data.bin"
#define OUTPUT_FILE "output_data.bin"

int main(int argc, char *argv[]) {
 int rank, size;
 MPI_Status status;
 MPI_File fh;
 MPI_Comm comm = MPI_COMM_WORLD;

 MPI_Init(&argc, &argv);
 MPI_Comm_rank(comm, &rank);
 MPI_Comm_size(comm, &size);

 // Define number of elements per process (for demo, use fixed size)
 int local_count = 1000;
 int total_count = local_count * size;

 // Allocate local buffers
 double *local_data = (double *)malloc(local_count * sizeof(double));
 double *local_result = (double *)malloc(local_count * sizeof(double));
 double *file_data = NULL;

 // Calculate file offset for this process (block decomposition)
 MPI_Offset offset = rank * local_count * sizeof(double);

 // Create a test data file (only on rank 0)
 if (rank == 0) {
 file_data = (double *)malloc(total_count * sizeof(double));
 for (int i = 0; i < total_count; i++) {
 file_data[i] = (double)i; // Sequential data 0, 1, 2, ...
 }

 MPI_File file;
 MPI_File_open(MPI_COMM_SELF, FILE_NAME, MPI_MODE_CREATE | MPI_MODE_WRONLY,
 MPI_INFO_NULL, &file);
 MPI_File_write(file, file_data, total_count, MPI_DOUBLE, &status);
 MPI_File_close(&file);
 free(file_data);
 printf("Rank 0: Created input file with %d elements\n", total_count);
 }

 // Synchronize to ensure file is created before reading
 MPI_Barrier(comm);

 // === PARALLEL FILE READ USING MPI-IO ===
 // Each process opens the same file but will see different portions
 int rc = MPI_File_open(comm, FILE_NAME, MPI_MODE_RDONLY, MPI_INFO_NULL, &fh);
 if (rc != MPI_SUCCESS) {
 char error_string[MPI_MAX_ERROR_STRING];
 int len;
 MPI_Error_string(rc, error_string, &len);
 if (rank == 0) printf("Error opening file: %s\n", error_string);
 MPI_Finalize();
 return 1;
 }

 // Set file view - defines which portion of file is visible to this process
 // Each process sees a contiguous block of 'local_count' doubles
 MPI_Datatype filetype;
 MPI_Type_contiguous(local_count, MPI_DOUBLE, &filetype);
 MPI_Type_commit(&filetype);

 // Set the file view for this process
 MPI_File_set_view(fh, offset, MPI_DOUBLE, filetype, "native", MPI_INFO_NULL);

 // Collective read - all processes participate for optimal performance
 MPI_File_read_all(fh, local_data, local_count, MPI_DOUBLE, &status);

 // Close the file
 MPI_File_close(&fh);

 printf("Rank %d: Read %d elements from file (offset=%lld)\n", 
 rank, local_count, (long long)offset);

 // === COMPUTATION PHASE ===
 // Each process computes on its local data (example: square each value)
 for (int i = 0; i < local_count; i++) {
 local_result[i] = local_data[i] * local_data[i];
 }

 // === PARALLEL FILE WRITE USING MPI-IO ===
 rc = MPI_File_open(comm, OUTPUT_FILE, 
 MPI_MODE_CREATE | MPI_MODE_WRONLY, 
 MPI_INFO_NULL, &fh);
 if (rc != MPI_SUCCESS) {
 char error_string[MPI_MAX_ERROR_STRING];
 int len;
 MPI_Error_string(rc, error_string, &len);
 if (rank == 0) printf("Error opening output file: %s\n", error_string);
 MPI_Finalize();
 return 1;
 }

 // Reset file view for writing
 MPI_File_set_view(fh, offset, MPI_DOUBLE, filetype, "native", MPI_INFO_NULL);

 // Collective write - all processes write their results concurrently
 MPI_File_write_all(fh, local_result, local_count, MPI_DOUBLE, &status);

 MPI_File_close(&fh);
 MPI_Type_free(&filetype);

 printf("Rank %d: Written results to output file\n", rank);

 // Cleanup
 free(local_data);
 free(local_result);

 MPI_Finalize();
 return 0;
}
